var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"휴우, 정말 힘이 세더군요.","JPN":"ふう、本当に力が強いんですね。","ENG":"Whew, she was really strong.","TWN":"呼，力氣還真不小呢。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"구속복을 입히는 것만으론 모자라 밧줄을 감아둬야 할 정도라니.","JPN":"拘束衣を着せたうえに、ロープで縛り付けるなんて。","ENG":"We had to tie her up with ropes because a straitjacket was not enough.","TWN":"只穿拘束服不夠，竟然還得用繩子把他綁起來。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"침식후유증에 대해서는 꽤 알고 있다고 생각했는데, 나도 저런 환자는 처음이었다네......","JPN":"侵食後遺症に関しては精通しているほうだと思っていたが、あんな患者は私も初めてだ……","ENG":"I thought I knew everything about about Corruption trauma, but I've never seen a patient like this.","TWN":"雖然我自認為對侵蝕後遺症很有瞭解，但這種患者還真是第一次……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"그 사람은 대체 무슨 진단명으로 불러야 할까요?","JPN":"あの患者の診断名は……？","ENG":"What should we diagnose her with?","TWN":"這個人患的病名到底叫什麼？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"글쎄. 하루 종일 침식체를 부르짖고, 환청까지 들린다는 걸 보면 불안장애의 일종 같긴 해.","JPN":"さあ。一日中、侵食体を連呼しているうえに幻聴まで聞こえてるようだから、一種の不安障害だろう。","ENG":"I'm not sure. Seeing how she's crying out for C.O. and having auditory hallucinations, it could be some sort of an anxiety disorder.","TWN":"這不好說，從他整天喊著侵蝕體，還有幻聽的樣子來看，應該是屬於焦慮症中的一種。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"불안장애라니......","JPN":"不安障害ですか……","ENG":"An anxiety disorder...","TWN":"焦慮症……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"그 발버둥치던 모습을 돌이켜보면 그건 너무 얌전한 표현 같은데 말이죠.","JPN":"それにしては、尋常じゃないほど暴れてました。","ENG":"That would be an understatement based on the way she was struggling.","TWN":"現在回想起他掙扎的樣子，那也算是夠安分的表現了。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"해리성 정체감 장애에, 침식체 공포증...... 같은 게 아닐까요?","JPN":"解離性同一障害と侵食体恐怖症……、ではないでしょうか？","ENG":"How about a dissociative identity disorder, on top of a C.O. phobia? What do you think?","TWN":"會不會是多重人格障礙加上侵蝕體恐懼症……？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"아니지. 그 환자가 두려워하는 건 머릿속에서 들린다는 목소리야.","JPN":"いや。あの患者は、頭の中から聞こえてくる声に怯えてる。","ENG":"No. The patient is afraid of the voices she's hearing in her head.","TWN":"不，那個患者害怕的是腦中聽到的聲音。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"침식체는 어디까지나 두려워하는 게 아닌 증오의 대상이고.","JPN":"侵食体はあくまでも、恐怖の対象ではなく憎悪の対象だ。","ENG":"She's not afraid of C.O., they are rather an object of hate.","TWN":"侵蝕體不是他恐懼，而是他憎惡的對象。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"환자는 그 목소리를, 무슨 이름으로 부르던 것 같던데요.","JPN":"患者はその声を、確か名前で呼んでいました。","ENG":"The patient seemed to be calling that voice by a certain name.","TWN":"患者好像稱那個聲音叫……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"그래, 오르카...... 라고 하더군.","JPN":"ああ、オルカ……、と呼んでいた。","ENG":"Yes, Orca... is what she said.","TWN":"對，奧爾卡……他是這麼說的。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"......범고래요? 바다에 사는?","JPN":"……シャチですか？あの、海の？","ENG":"The killer whale? That lives in the ocean?","TWN":"……是虎鯨嗎？在海裡的那個？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"뭐, 그렇게 읽을 수도 있겠지.","JPN":"ああ、そうとも言えるな。","ENG":"Well, I suppose you could call it that.","TWN":"這個嘛，是也可以這樣念啦。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"하지만 야전 의무병 시절에 내가 들었던 오르카란건......","JPN":"だが野戦衛生兵だった頃、私が聞いたオルカというのは……","ENG":"But what I heard while working out in the fields as a medic...","TWN":"但是我在野戰醫療兵時期，聽到的奧爾卡是……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>선생님! 302호실 중환자가 도망쳤습니다!</color>","JPN":"<color=#ffd34c>先生！302号室の患者が脱走しました！</color>","ENG":"<color=#ffd34c>Doctor! The critical patient from room 302 escaped!</color>","TWN":"<color=#ffd34c>醫生，302室的重症患者逃跑了！</color>"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"......뭐라고! 하지만 어떻게?","JPN":"……何だと？しかし、どうやって？","ENG":"What?! But how?","TWN":"……你說什麼！可是這怎麼可能？！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>부, 분명 아무 것도 없었는데, 갑자기 침식체가 나타났다더니 손에서 칼이 튀어나와선......</color>","JPN":"<color=#ffd34c>た、確かに何も持っていなかったのに、急に侵食体が現れたといって手からナイフを……</color>","ENG":"<color=#ffd34c>Th-there was nothing there, but she suddenly shouted that a C.O. had appeared, and pulled out a knife...</color>","TWN":"<color=#ffd34c>本、本來一切都很好，但侵蝕體突然出現後，患者的手上就出現了刀……</color>"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"칼이라고?! 누구 다친 사람 있나?","JPN":"ナイフだと！ケガ人は！？","ENG":"A knife?! Is anyone hurt?","TWN":"刀？！有人受傷了嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};